import{_ as a,o as l,c as r,f as t}from"./chunks/framework.BVATNCDi.js";const u=JSON.parse('{"title":"3d图形渲染教程开坑前言","description":"","frontmatter":{"layout":"post","title":"3d图形渲染教程开坑前言","date":"2026-01-04T15:48:48.000Z","tags":["3D渲染","OpenGL"],"image_url":"https://enhiucyodopknrbdtswy.supabase.co/storage/v1/object/public/resources/img/2026-01-04%20234603.png","summary":"系列将让你高度理解3d图形渲染的本质和原理，使用OpenGL规范构建自己的3D渲染引擎。","top":false},"headers":[{"level":1,"title":"基础认知","slug":"基础认知","link":"#基础认知","children":[{"level":2,"title":"世界（World）","slug":"世界-world","link":"#世界-world","children":[]},{"level":2,"title":"模型（Model）","slug":"模型-model","link":"#模型-model","children":[]},{"level":2,"title":"灯光（Light）","slug":"灯光-light","link":"#灯光-light","children":[]},{"level":2,"title":"相机（Camera）","slug":"相机-camera","link":"#相机-camera","children":[]},{"level":2,"title":"渲染（Render）","slug":"渲染-render","link":"#渲染-render","children":[]}]}],"relativePath":"posts/learn3d-before.md","filePath":"posts/learn3d-before.md"}'),o={name:"posts/learn3d-before.md"};function i(d,e,n,s,p,h){return l(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="基础认知" tabindex="-1">基础认知 <a class="header-anchor" href="#基础认知" aria-label="Permalink to &quot;基础认知&quot;">​</a></h1><p>什么是渲染？</p><p>就是将画面呈现在电子屏幕上的过程，而3d图形渲染就是让3d画面在2d屏幕上显示出来。</p><p>人眼是一种例子，我们所&quot;看&quot;到的世界是3d的，而我们所感知到的画面是2d的。为了模拟这种效果，我们需要创造一个虚拟世界来承载必不可少的：模型，灯光，相机。他们相互作用的过程就叫渲染。</p><h2 id="世界-world" tabindex="-1">世界（World） <a class="header-anchor" href="#世界-world" aria-label="Permalink to &quot;世界（World）&quot;">​</a></h2><p>世界是承载所有实体的地方，为了描述实体间的相对位置而存在。以（0,0,0）点为世界原点，建立三维坐标系，赋予实体以世界坐标（x,y,z）。</p><h2 id="模型-model" tabindex="-1">模型（Model） <a class="header-anchor" href="#模型-model" aria-label="Permalink to &quot;模型（Model）&quot;">​</a></h2><p>真正要渲染的对象，由许多顶点（Vertex）组成，并且每个顶点都有世界位置和一些其他属性，比如颜色。将这些顶点按规定连成体，便形成了完整的模型。设置模型顶点的位置这个过程被称作建模。</p><p>（由于模型文件有多种格式，请自行点击跳转至特定模型文件格式的文章）</p><ul><li>glTF</li><li>fbx</li><li>pmx</li><li>VRM</li></ul><h2 id="灯光-light" tabindex="-1">灯光（Light） <a class="header-anchor" href="#灯光-light" aria-label="Permalink to &quot;灯光（Light）&quot;">​</a></h2><p>大致被分为两种：点光和平行光。顾名思义，由一个点发散得来的光线称为点光，可想象为一个手电筒；距离足够远的光源得到的光线被粗略定义为平行光，显然太阳的自然光就是。而为了让模型能够更好地被渲染，世界里至少要有一个光源，最好是模拟自然光的平行光。</p><p>通常点光需要有世界位置而平行光只需要向量即可</p><h2 id="相机-camera" tabindex="-1">相机（Camera） <a class="header-anchor" href="#相机-camera" aria-label="Permalink to &quot;相机（Camera）&quot;">​</a></h2><p>光线发出后经过模型的反射后到达的终点，即接收画面的东西，也是我们观察这个所谓的虚拟世界的入口。</p><p>拥有一个世界坐标和相机屏幕（宽度和高度）</p><h2 id="渲染-render" tabindex="-1">渲染（Render） <a class="header-anchor" href="#渲染-render" aria-label="Permalink to &quot;渲染（Render）&quot;">​</a></h2><p>以上实体经过一系列相互作用最终使得3D模型能够在2D屏幕上表现出来的过程，叫3D图形渲染，简称渲染。</p><p>这个“相互作用”包含从模型的顶点位置出发，经历很多复杂的计算，诸如光线到达模型表面是如何被反射的，相机是如何映射模型的画面的，以及如何实时修改模型参数以达到3d动画的效果，本系列都会讲到。</p>',19)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
